-- Added post-creation as required by the task specification. -- DEFAULT CURRENT_DATE ensures all new rows are stamped automatically. -- ADD COLUMN IF NOT EXISTS makes the statement idempotent on re-runs.

ALTER TABLE bookstore.publishers ADD COLUMN IF NOT EXISTS record_ts DATE NOT NULL DEFAULT CURRENT_DATE; ALTER TABLE bookstore.authors ADD COLUMN IF NOT EXISTS record_ts DATE NOT NULL DEFAULT CURRENT_DATE; ALTER TABLE bookstore.genres ADD COLUMN IF NOT EXISTS record_ts DATE NOT NULL DEFAULT CURRENT_DATE; ALTER TABLE bookstore.books ADD COLUMN IF NOT EXISTS record_ts DATE NOT NULL DEFAULT CURRENT_DATE; ALTER TABLE bookstore.book_authors ADD COLUMN IF NOT EXISTS record_ts DATE NOT NULL DEFAULT CURRENT_DATE; ALTER TABLE bookstore.book_genres ADD COLUMN IF NOT EXISTS record_ts DATE NOT NULL DEFAULT CURRENT_DATE; ALTER TABLE bookstore.customers ADD COLUMN IF NOT EXISTS record_ts DATE NOT NULL DEFAULT CURRENT_DATE; ALTER TABLE bookstore.orders ADD COLUMN IF NOT EXISTS record_ts DATE NOT NULL DEFAULT CURRENT_DATE; ALTER TABLE bookstore.order_items ADD COLUMN IF NOT EXISTS record_ts DATE NOT NULL DEFAULT CURRENT_DATE; ALTER TABLE bookstore.reviews ADD COLUMN IF NOT EXISTS record_ts DATE NOT NULL DEFAULT CURRENT_DATE;

-- Backfill record_ts for any rows that pre-existed the column addition. -- When ADD COLUMN sets the default, existing rows receive the value automatically -- in PostgreSQL; these UPDATEs serve as an explicit safety net. UPDATE bookstore.publishers SET record_ts = CURRENT_DATE WHERE record_ts IS NULL; UPDATE bookstore.authors SET record_ts = CURRENT_DATE WHERE record_ts IS NULL; UPDATE bookstore.genres SET record_ts = CURRENT_DATE WHERE record_ts IS NULL; UPDATE bookstore.books SET record_ts = CURRENT_DATE WHERE record_ts IS NULL; UPDATE bookstore.book_authors SET record_ts = CURRENT_DATE WHERE record_ts IS NULL; UPDATE bookstore.book_genres SET record_ts = CURRENT_DATE WHERE record_ts IS NULL; UPDATE bookstore.customers SET record_ts = CURRENT_DATE WHERE record_ts IS NULL; UPDATE bookstore.orders SET record_ts = CURRENT_DATE WHERE record_ts IS NULL; UPDATE bookstore.order_items SET record_ts = CURRENT_DATE WHERE record_ts IS NULL; UPDATE bookstore.reviews SET record_ts = CURRENT_DATE WHERE record_ts IS NULL;

